// Fetch all incoming items
const items = $input.all();

// Extract the raw row data (each item.json is one row)
const rawRows = items.map(item => item.json);

// Bundle everything into a single field
const payload = { rows: rawRows };

// Return a single output item whose json contains your full dataset
return [{ json: { data: payload } }];

// Assume the AI agent returned a single item and its text is in item.json.output
const items = $input.all();
const aiText = String(items[0].json.output ?? '');

// Remove markdown fences, then fall back to the first {...} block if the model added prose
let jsonString = aiText.replace(/```(?:json)?\s*([\s\S]*?)```/i, '$1').trim();
if (!jsonString.startsWith('{')) {
  const match = jsonString.match(/\{[\s\S]*\}/);
  if (match) jsonString = match[0];
}

let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  throw new Error('Failed to parse JSON from AI output: ' + e.message + ' | raw: ' + aiText.slice(0, 300));
}

const date = parsed.date || new Date().toISOString().slice(0, 10);
const replenishments = Array.isArray(parsed.replenishments) ? parsed.replenishments : [];
if (replenishments.length === 0) {
  throw new Error('AI returned no replenishments. Raw: ' + aiText.slice(0, 300));
}

// Emit one n8n item per product so Google Sheets appends one row each
return replenishments.map(r => ({
  json: {
    Date: date,
    Item: r.item,
    'Current Stock (kg)': Number(r.current_stock_kg),
    Status: r.status,
    'Replenishment (kg)': Number(r.replenishment_kg),
  },
}));

// Collapse the per-product rows into ONE item so Gmail sends a single email
const rows = $input.all().map(i => i.json);
const date = rows[0]?.Date ?? new Date().toISOString().slice(0, 10);
const low = rows.filter(r => String(r.Status).toUpperCase().includes('LOW'));

const SHEET_URL = 'https://docs.google.com/spreadsheets/d/SPREADSHEET_ID_PLACEHOLDER/edit?usp=sharing';

const cell = v => `<td style="padding:6px 10px;border:1px solid #ddd">${v}</td>`;
const body = rows.map(r =>
  `<tr>${cell(r.Item)}${cell(r['Current Stock (kg)'])}${cell(r.Status)}${cell(r['Replenishment (kg)'])}</tr>`
).join('');

const table = `<table style="border-collapse:collapse;font-family:Arial,sans-serif;font-size:14px">
<tr style="background:#f2f2f2">
  <th style="padding:6px 10px;border:1px solid #ddd">Item</th>
  <th style="padding:6px 10px;border:1px solid #ddd">Current Stock (kg)</th>
  <th style="padding:6px 10px;border:1px solid #ddd">Status</th>
  <th style="padding:6px 10px;border:1px solid #ddd">Replenishment (kg)</th>
</tr>${body}</table>`;

const orderLines = low.length
  ? low.map(r => `<li>${r.Item}: <b>${r['Replenishment (kg)']} kg</b></li>`).join('')
  : '<li>No items below the 20 kg threshold. No order required.</li>';

const subject = low.length
  ? `Stock replenishment order - ${date} (${low.length} item${low.length > 1 ? 's' : ''})`
  : `Inventory check ${date} - all stock levels OK`;

const message = `Dear Supplier,<br><br>
I want to purchase this order.<br><br>
<b>Inventory date:</b> ${date}<br><br>
<b>Order required:</b><ul>${orderLines}</ul>
<b>Full stock audit:</b><br>${table}<br>
<b>Sheet link with all data:</b><br>
<a href="${SHEET_URL}">Click here to view the data</a><br><br>
Thanks,<br>Inventory Management Agent`;

return [{ json: { date, subject, message, low_stock_count: low.length } }];
